public ValueMarker(double value, Paint paint, Stroke stroke, Paint outlinePaint, Stroke outlineStroke, float alpha) {
        super(paint, stroke, outlinePaint, outlineStroke, alpha);
        this.value = value;
        if (outlinePaint == null || stroke == null || outlineStroke == null) {
            throw new IllegalArgumentException("ValueMarker must have non-null paint, stroke, and outlineStroke");
        }
    }
